["Initialization"] = "function (modTable)\n    ---@class PlaterCastBar : StatusBar\n    ---@field barTexture Texture\n    ---@field interrupted boolean\n    ---@field IsInterrupted boolean\n    ---@field interruptOverlayBar StatusBar\n    ---@field notInterruptible boolean|nil\n    \n    ---@class PlaterUnitFrame : Frame\n    ---@field unit string\n    ---@field castBar PlaterCastBar\n    \n    -- C_CVar.SetCVar(\"nameplateShowOffscreen\", 1)\n    \n    local playerClass = select(3, UnitClass(\"player\"))\n    \n    local classInterruptMap = {\n        [1] = { { id = 6552 } }, -- Warrior\n        [2] = { { id = 96231 } }, -- Paladin\n        [3] = { { id = 147362 }, {id = 187707} }, -- Hunter\n        [4] = { { id = 1766 } }, -- Rogue\n        [5] = { { id = 15487 } }, -- Priest\n        [6] = { { id = 47528 } }, -- Death Knight\n        [7] = { { id = 57994 } }, -- Shaman\n        [8] = { { id = 2139 } }, -- Mage\n        [9] = {\n            {\n                id = 89766,\n                override = function()\n                    return C_SpellBook.IsSpellKnown(89766, Enum.SpellBookSpellBank.Pet)\n                end,\n            },\n            {\n                id = 19647,\n                override = function()\n                    return C_SpellBook.IsSpellKnown(19647, Enum.SpellBookSpellBank.Pet)\n                end,\n            },\n            {\n                id = 132409,\n                override = function()\n                    -- incomplete as C_UnitAuras.GetPlayerAuraBySpellID(196099) ~= nil is missing but won't work in restricted environments\n                    return C_SpellBook.IsSpellKnownOrInSpellBook(132409)\n                end,\n            },\n        }, -- Warlock\n        [10] = { { id = 116705 } }, -- Monk\n        [11] = { { id = 78675 }, { id = 106839 } }, -- Druid\n        [12] = { { id = 183752 } }, -- Demon Hunter\n        [13] = { { id = 351338 } }, -- Evoker\n    }\n    \n    local eligibleInterrupts = classInterruptMap[playerClass]\n    \n    ---@return number|nil\n    local function GetInterruptInfo()\n        for i = 1, #eligibleInterrupts do\n            local info = eligibleInterrupts[i]\n            \n            if info.override and info.override() then\n                return info.id\n            end\n            \n            if C_SpellBook.IsSpellKnown(info.id) then\n                return info.id\n            end\n        end\n        \n        return nil\n    end\n    \n    local colors = {\n        uninterruptible = CreateColor(unpack(modTable.config.colorProtected)),\n        interruptAvailable = CreateColor(unpack(modTable.config.colorInterruptAvailable)),\n        noInterrupt = CreateColor(unpack(modTable.config.colorNoInterrupt)),\n    }\n    \n    ---@param unitId string\n    ---@param unitFrame PlaterUnitFrame\n    function modTable.EnhancedCastBar(unitId, unitFrame)\n        if not modTable.config.showInterruptColor then\n            return\n        end\n        \n        local castBar = unitFrame.castBar\n        \n        if castBar.IsInterrupted or castBar.interrupted or castBar.notInterruptible == nil then\n            return\n        end\n        \n        local interruptId = GetInterruptInfo()\n        local nextColor = colors.uninterruptible\n        \n        if interruptId == nil then\n            nextColor = colors.noInterrupt\n        else\n            if modTable.config.enableInterruptTick then\n                if castBar.interruptOverlayBar == nil then\n                    local bar = CreateFrame(\"StatusBar\", nil, castBar)\n                    bar:SetStatusBarTexture(\"Interface/AddOns/Plater/images/transparent.tga\")\n                    bar:SetClipsChildren(true)\n                    bar:SetFrameLevel(castBar:GetFrameLevel() + 4)\n                    bar:ClearAllPoints()\n                    bar:SetPoint(\"LEFT\", castBar:GetStatusBarTexture(), \"RIGHT\")\n                    \n                    local mask = castBar:CreateMaskTexture()\n                    mask:SetPoint(\"CENTER\")\n                    mask:SetTexture(\n                        \"Interface/AddOns/Plater/images/square_white.tga\",\n                        \"CLAMPTOBLACKADDITIVE\",\n                        \"CLAMPTOBLACKADDITIVE\"\n                    )\n                    mask:SetTextureSliceMargins(1, 1, 1, 1)\n                    \n                    local tick = bar:CreateTexture()\n                    tick:SetColorTexture(0, 1, 0)\n                    tick:SetPoint(\"CENTER\", bar:GetStatusBarTexture(), \"RIGHT\")\n                    tick:AddMaskTexture(mask)\n                    \n                    local width, height = castBar:GetSize()\n                    PixelUtil.SetSize(mask, width, height)\n                    PixelUtil.SetSize(bar, width, height)\n                    PixelUtil.SetSize(tick, 2, height)\n                    \n                    bar.tick = tick\n                    castBar.interruptOverlayBar = bar\n                    \n                    bar:Show()\n                    \n                    local function RunUpdate(castingInfo, cooldownInfo)\n                        if castBar.IsInterrupted or castBar.interrupted or castBar.notInterruptible == nil then\n                            castBar.interruptOverlayBar:Hide()\n                            \n                            return\n                        end\n                        \n                        castBar.interruptOverlayBar:SetMinMaxValues(0, castingInfo:GetTotalDuration())\n                        castBar.interruptOverlayBar:SetValue(cooldownInfo:GetRemainingDuration())\n                        castBar.interruptOverlayBar:SetAlphaFromBoolean(\n                            cooldownInfo:IsZero(),\n                            0,\n                            C_CurveUtil.EvaluateColorValueFromBoolean(castBar.notInterruptible, 0, 1)\n                        )\n                    end\n                    \n                    -- please forgive me for this\n                    local poorMansHookScriptTimer = nil\n                    \n                    hooksecurefunc(castBar, \"Show\", function(self)\n                            if poorMansHookScriptTimer ~= nil then\n                                poorMansHookScriptTimer:Cancel()\n                                poorMansHookScriptTimer = nil\n                            end\n                            \n                            self.interruptOverlayBar:Show()\n                            \n                            if not modTable.config.enableInterruptTick then\n                                return\n                            end\n                            \n                            poorMansHookScriptTimer = C_Timer.NewTicker(0.1, function()\n                                    local castingInfo = UnitCastingDuration(self.unit)\n                                    if castingInfo == nil then\n                                        castingInfo = UnitChannelDuration(self.unit)\n                                    end\n                                    \n                                    if castingInfo == nil then\n                                        return\n                                    end\n                                    \n                                    local cooldownInfo = C_Spell.GetSpellCooldownDuration(interruptId)\n                                    \n                                    RunUpdate(castingInfo, cooldownInfo)\n                            end)\n                    end)\n                    \n                    hooksecurefunc(castBar, \"Hide\", function(self)\n                            if poorMansHookScriptTimer ~= nil then\n                                poorMansHookScriptTimer:Cancel()\n                                poorMansHookScriptTimer = nil\n                            end\n                    end)\n                end\n                \n                -- can theoretically move this into on update too but there's no reason for it to run that often\n                local isChannel = UnitChannelInfo(unitId) ~= nil\n                \n                castBar.interruptOverlayBar:ClearAllPoints()\n                if isChannel then\n                    castBar.interruptOverlayBar:SetFillStyle(Enum.StatusBarFillStyle.Reverse)\n                    castBar.interruptOverlayBar:SetPoint(\"RIGHT\", castBar.barTexture, \"RIGHT\")\n                    castBar.interruptOverlayBar.tick:SetPoint(\n                        \"CENTER\",\n                        castBar.interruptOverlayBar:GetStatusBarTexture(),\n                        \"LEFT\"\n                    )\n                else\n                    castBar.interruptOverlayBar:SetFillStyle(Enum.StatusBarFillStyle.Standard)\n                    castBar.interruptOverlayBar:SetPoint(\"LEFT\", castBar:GetStatusBarTexture(), \"RIGHT\")\n                    castBar.interruptOverlayBar.tick:SetPoint(\n                        \"CENTER\",\n                        castBar.interruptOverlayBar:GetStatusBarTexture(),\n                        \"RIGHT\"\n                    )\n                end\n            end\n            \n            local cooldownInfo = C_Spell.GetSpellCooldownDuration(interruptId)\n            local bool = cooldownInfo:IsZero()\n            \n            local interruptAvailableR, interruptAvailableG, interruptAvailableB = colors.interruptAvailable:GetRGB()\n            local noInterruptR, noInterruptG, noInterruptB = colors.noInterrupt:GetRGB()\n            \n            local r = C_CurveUtil.EvaluateColorValueFromBoolean(bool, interruptAvailableR, noInterruptR)\n            local g = C_CurveUtil.EvaluateColorValueFromBoolean(bool, interruptAvailableG, noInterruptG)\n            local b = C_CurveUtil.EvaluateColorValueFromBoolean(bool, interruptAvailableB, noInterruptB)\n            \n            nextColor = CreateColor(r, g, b)\n        end\n        \n        castBar.barTexture:SetVertexColorFromBoolean(castBar.notInterruptible, colors.uninterruptible, nextColor)\n    end\nend",
["Constructor"] = "function (self, unitId, unitFrame, envTable, modTable) end",
},
