["Hooks"] = {
["Initialization"] = "function (self, unitId, unitFrame, envTable, modTable)\n    function Plater.UpdateLifePercentText(healthBar, unitId, showHealthAmount, showPercentAmount, showDecimals) -- ~health\n        --get the cached health amount for performance\n        local currentHealth, maxHealth, currentHealthMissing, currentHealthPercent =\n        healthBar.currentHealth,\n        healthBar.currentHealthMax,\n        healthBar.currentHealthMissing,\n        healthBar.currentHealthPercent\n        \n        currentHealth = AbbreviateNumbers(currentHealth)\n        \n        if showHealthAmount and showPercentAmount then\n            if showDecimals then\n                healthBar.lifePercent:SetText(format(\"%s | %.1f%%\", currentHealth, currentHealthPercent))\n            else\n                healthBar.lifePercent:SetText(format(\"%s | %d%%\", currentHealth, currentHealthPercent))\n            end\n        elseif showHealthAmount then\n            healthBar.lifePercent:SetText(currentHealth)\n        elseif showPercentAmount then\n            if showDecimals then\n                healthBar.lifePercent:SetText(format(\"%.1f%%\", currentHealthPercent))\n            else\n                healthBar.lifePercent:SetText(format(\"%d%%\", currentHealthPercent))\n            end\n        else\n            healthBar.lifePercent:SetText(\"\")\n        end\n    end\nend",
},
