["Hooks"] = {
["Cast Start"] = "function (self, unitId, unitFrame, envTable, modTable)\n    local unit = unitId or unitFrame.unit\n    \n    if unit == nil then\n        return\n    end\n    \n    local spellId = select(9, UnitCastingInfo(unit)) or select(8, UnitChannelInfo(unit))\n    \n    if spellId == nil then\n        return\n    end\n    \n    local isImportant = C_Spell.IsSpellImportant(spellId)\n    \n    if unitFrame.FrameShake == nil then\n        local flashDuration = 0.8\n        local shakeDuration = 0.2\n        local shakeAmplitude = 5\n        local shakeFrequency = 40\n        \n        ---@type Texture\n        local backGroundFlashTexture = Plater:CreateImage(\n            self,\n            [[Interface\\ACHIEVEMENTFRAME\\UI-Achievement-Alert-Glow]],\n            self:GetWidth() + 40,\n            self:GetHeight() + 20,\n            \"background\",\n            { 0, 400 / 512, 0, 170 / 256 }\n        )\n        backGroundFlashTexture:SetBlendMode(\"ADD\")\n        backGroundFlashTexture:SetDrawLayer(\"OVERLAY\", 7)\n        backGroundFlashTexture:SetPoint(\"CENTER\", self, \"CENTER\")\n        backGroundFlashTexture:SetVertexColor(0, 0, 0)\n        backGroundFlashTexture:Hide()\n        \n        unitFrame.FrameShake = Plater:CreateFrameShake(\n            unitFrame,\n            shakeDuration,\n            shakeAmplitude,\n            shakeFrequency,\n            false,\n            false,\n            0,\n            1,\n            0.05,\n            0.1,\n            Plater.GetPoints(unitFrame)\n        )\n        \n        ---@type AnimationGroup\n        unitFrame.BackgroundFlash = Plater:CreateAnimationHub(backGroundFlashTexture, function()\n                backGroundFlashTexture:Show()\n            end, function()\n                backGroundFlashTexture:Hide()\n        end)\n        \n        local fadeIn = Plater:CreateAnimation(unitFrame.BackgroundFlash, \"ALPHA\", 1, flashDuration / 2, 0, 1)\n        local fadeOut = Plater:CreateAnimation(unitFrame.BackgroundFlash, \"ALPHA\", 2, flashDuration / 2, 1, 0)\n        \n        fadeIn:SetDuration(flashDuration / 2)\n        fadeOut:SetDuration(flashDuration / 2)\n        \n        unitFrame.FrameShake.OriginalAmplitude = shakeAmplitude\n        unitFrame.FrameShake.OriginalDuration = shakeDuration\n        unitFrame.FrameShake.OriginalFrequency = shakeFrequency\n        \n        unitFrame.dotAnimation =\n        Plater.PlayDotAnimation(unitFrame.castBar, 5, Plater:ParseColors({ 144, 144, 144 }), 8, 3)\n    end\n    \n    Plater.FlashNameplateBorder(unitFrame, 0.05)\n    unitFrame.healthBar.HealthFlashFrame:SetAlphaFromBoolean(isImportant)\n    \n    Plater.FlashNameplateBody(unitFrame, \"\", 0.075)\n    unitFrame.BodyFlashFrame:SetAlphaFromBoolean(isImportant)\n    \n    unitFrame.dotAnimation:SetAlphaFromBoolean(isImportant)\nend",
},
