ackgroundFlash, \"ALPHA\", 2, flashDuration / 2, 1, 0)\n        \n        fadeIn:SetDuration(flashDuration / 2)\n        fadeOut:SetDuration(flashDuration / 2)\n        \n        unitFrame.FrameShake.OriginalAmplitude = shakeAmplitude\n        unitFrame.FrameShake.OriginalDuration = shakeDuration\n        unitFrame.FrameShake.OriginalFrequency = shakeFrequency\n        \n        unitFrame.dotAnimation =\n        Plater.PlayDotAnimation(unitFrame.castBar, 5, Plater:ParseColors({ 144, 144, 144 }), 8, 3)\n    end\n    \n    Plater.FlashNameplateBorder(unitFrame, 0.05)\n    unitFrame.healthBar.HealthFlashFrame:SetAlphaFromBoolean(isImportant)\n    \n    Plater.FlashNameplateBody(unitFrame, \"\", 0.075)\n    unitFrame.BodyFlashFrame:SetAlphaFromBoolean(isImportant)\n    \n    unitFrame.dotAnimation:SetAlphaFromBoolean(isImportant)\nend",
