["Hooks"] = {
["Nameplate Added"] = "function (self, unitId, unitFrame, envTable, modTable)\n    envTable.unitIsCaster = false\nend\n\n\n",
["Initialization"] = "function (modTable)\n    if select(4, GetBuildInfo()) < 120000 then\n        function modTable.UpdateColor()\n            -- retail compatibility, just not gonna do anything here\n        end\n        \n        return\n    end\n    \n    local function DeriveColor(envTable, unitFrame)\n        local unitIsPlayer = unitFrame.ActorType == \"friendlyplayer\" or unitFrame.ActorType == \"enemyplayer\"\n        \n        if unitIsPlayer then\n            return nil\n        end\n        \n        local playerLevel = UnitLevel(\"player\")\n        local level = UnitEffectiveLevel(unitFrame.unit)\n        local isBoss = level == playerLevel + 2 or UnitEffectiveLevel(unitFrame.unit) == -1\n        \n        if isBoss then\n            return modTable.config.boss\n        end\n        \n        local isLieutenant = level == playerLevel + 1\n        or unitFrame.namePlateIsBossMob\n        or UnitIsLieutenant(unitFrame.unit)\n        \n        if isLieutenant then\n            return modTable.config.lieutenant\n        end\n        \n        -- short circuit to skip below\n        if envTable.unitIsCaster then\n            return modTable.config.caster\n        end\n        \n        local powerMax = UnitPowerMax(unitFrame.unit, Enum.PowerType.Mana)\n        local isCaster = UnitClassBase(unitFrame.unit) == \"PALADIN\" or (not issecretvalue(powerMax) and powerMax > 0)\n        \n        if isCaster then\n            return modTable.config.caster\n        end\n        \n        local isElite = unitFrame.namePlateClassification == \"elite\" or unitFrame.namePlateClassification == \"rareelite\"\n        \n        if isElite then\n            return modTable.config.regular\n        end\n        \n        return nil\n    end\n    \n    function modTable.UpdateColor(unitFrame, envTable)\n        if not unitFrame or unitFrame.IsNpcWithoutHealthbar or unitFrame.IsFriendlyPlayerWithoutHealthbar then\n            return\n        end\n        \n        if InCombatLockdown() then\n            if unitFrame.namePlateThreatIsTanking and not Plater.PlayerIsTank then\n                return\n            end\n            \n            if not unitFrame.namePlateThreatIsTanking and Plater.PlayerIsTank then\n                return\n            end\n        end\n        \n        local color = DeriveColor(envTable, unitFrame)\n        \n        if color == nil then\n            return\n        end\n        \n        Plater.SetNameplateColor(unitFrame, color)\n    end\nend",
["Nameplate Updated"] = "function (self, unitId, unitFrame, envTable, modTable)\n    modTable.UpdateColor (unitFrame, envTable)\nend",
},
