ckdown() then\n            if unitFrame.namePlateThreatIsTanking and not Plater.PlayerIsTank then\n                return\n            end\n            \n            if not unitFrame.namePlateThreatIsTanking and Plater.PlayerIsTank then\n                return\n            end\n        end\n        \n        local color = DeriveColor(envTable, unitFrame)\n        \n        if color == nil then\n            return\n        end\n        \n        Plater.SetNameplateColor(unitFrame, color)\n    end\nend",
